const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const filePath = item.path;
const fileName = item.fileName;
const fileExt = path.extname(fileName).toLowerCase();

let textContent = '';

if (fileExt === '.txt') {
  textContent = fs.readFileSync(filePath, 'utf8');
} else if (fileExt === '.pdf') {
  // TODO: Install pdf-parse via npm for full extraction
  textContent = `[PDF content from ${fileName} - install pdf-parse for full extraction]`;
} else if (fileExt === '.docx') {
  // TODO: Install mammoth via npm for full extraction
  textContent = `[DOCX content from ${fileName} - install mammoth for full extraction]`;
} else if (fileExt === '.pptx') {
  // TODO: Install pptx-parser for full extraction
  textContent = `[PPTX content from ${fileName} - install pptx-parser for full extraction]`;
}

return [{
  json: {
    ...item,
    textContent: textContent,
    fileType: fileExt.replace('.', '')
  }
}];

const item = $input.first().json;
const textContent = item.textContent;

const prompt = `Based on this lecture content, please create:

1. A comprehensive summary (300-500 words) that captures the main points and key takeaways
2. 10 review questions with detailed answers to test understanding
3. 15 flashcards in the format "Q: [question] | A: [answer]"
4. Key concepts and their relationships (as a list)
5. Suggested related topics to explore

Lecture Content:
${textContent}

Please structure your response with clear headers for each section.`;

return [{
  json: {
    ...item,
    geminiPrompt: prompt,
    contentType: 'lecture'
  }
}];

