const item = $input.first().json;
const textContent = item.textContent;

const prompt = `Please analyse this study material and provide:

1. A concise summary of the main content
2. Key points and takeaways
3. Review questions to test understanding
4. Suggested study strategies for this material

Content:
${textContent}`;

return [{
  json: {
    ...item,
    geminiPrompt: prompt,
    contentType: 'general'
  }
}];

// Parse Gemini's response
const response = $input.first().json;
const originalData = $input.first().json;

// Gemini response structure: candidates[0].content.parts[0].text
const content = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';

if (!content) {
  throw new Error('Empty response from Gemini API. Check your API key and quota.');
}

// Split into rough sections by double newline
const sections = content.split(/\n#{1,3} /).filter(s => s.trim());

return [{
  json: {
    ...originalData,
    geminiResponse: content,
    parsedResponse: {
      full: content,
      summary: sections[0] || '',
      questions: sections[1] || '',
      flashcards: sections[2] || '',
      concepts: sections[3] || '',
      relatedTopics: sections[4] || ''
    }
  }
}];

// Format content for Obsidian markdown
const data = $input.first().json;
const parsed = data.parsedResponse;
const now = new Date();
const dateStr = now.toISOString().split('T')[0];

const markdown = `---
type: ${data.contentType}-notes
course: "${data.courseName || 'Unknown'}"
date: ${dateStr}
source: ${data.fileName}
tags: [${data.courseName || 'study'}, ${data.contentType}, ai-generated, gemini]
---

# ${data.fileName.replace(/\.[^/.]+$/, '')}

## 📝 Summary
${parsed.summary}

## ❓ Review Questions
${parsed.questions}

## 🎴 Flashcards
${parsed.flashcards}

## 🧠 Key Concepts
${parsed.concepts}

## 🔗 Related Topics
${parsed.relatedTopics}

## 📎 Original Material
![[${data.fileName}]]

---
*Generated on: ${now.toISOString()}*
*Powered by: Google Gemini AI*
`;

const safeName = data.fileName.replace(/\.[^/.]+$/, '').replace(/[^a-zA-Z0-9 _-]/g, '_');

return [{
  json: {
    ...data,
    markdownContent: markdown,
    noteName: safeName + '.md',
    noteDate: dateStr
  }
}];
